mapper.insert:
insert into ai_token_usage (
    id, model_name, purpose, prompt_tokens, completion_tokens, total_tokens,
    user_id, user_code, conversation_id, estimated_cost, model_base_url, duration_ms, created_at
) values (
    #{id}, #{modelName}, #{purpose}, #{promptTokens}, #{completionTokens}, #{totalTokens},
    #{userId}, #{userCode}, #{conversationId}, #{estimatedCost}, #{modelBaseUrl}, #{durationMs}, #{createdAt}
)

mapper.select:
select id, model_name, purpose, prompt_tokens, completion_tokens, total_tokens,
       user_id, user_code, conversation_id, estimated_cost, model_base_url, duration_ms, created_at
from ai_token_usage
where created_at between #{startTime} and #{endTime}
  and deleted = 0

  and model_name = #{modelName}


  and purpose = #{purpose}

order by created_at desc
limit #{limit} offset #{offset}
